// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UxExecutionSession) predicate.UxExecutionSession {
	return predicate.UxExecutionSession(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UxExecutionSession) predicate.UxExecutionSession {
	return predicate.UxExecutionSession(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UxExecutionSession) predicate.UxExecutionSession {
	return predicate.UxExecutionSession(sql.NotPredicates(p))
}
